+
+/// Quality rating for training data filtering (DPO-Lite)
+/// Allows the system to skip mistakes and boost corrections during training.
+pub const Quality = enum(u8) {
+    standard = 0, // Normal training weight (1.0x)
+    rejection = 1, // BAD response - skip in training (0.0x weight)
+    gold_standard = 2, // GREAT response - boost weight (2.0x)
+
+    pub fn toWeight(self: Quality) f32 {
+        return switch (self) {
+            .standard => 1.0,
+            .rejection => 0.0, // Skip entirely
+            .gold_standard => 2.0, // Double weight
+        };
+    }
+};
