+    /// Mark the most recent response as a rejection (bad output, don't train on it)
+    /// Called when user corrects the model: "/no" or thumbs-down
+    pub fn markLastAsRejection(self: *ConversationLogger) !void {
+        try self.updateLastQuality(.rejection);
+    }
+
+    /// Mark the most recent response as gold standard (excellent, boost training weight)
+    /// Called after user confirms good output: "/yes" or thumbs-up
+    pub fn markLastAsGoldStandard(self: *ConversationLogger) !void {
+        try self.updateLastQuality(.gold_standard);
+    }
+
+    /// Update quality of most recent event by rewriting the last line
+    fn updateLastQuality(self: *ConversationLogger, quality: Quality) !void {
+        // Read the current log file
+        const file = std.fs.cwd().openFile(self.log_path, .{ .mode = .read_write }) catch |err| {
+            if (err == error.FileNotFound) return error.NoRecentEntry;
+            return err;
+        };
+        defer file.close();
+
+        const content = try file.readToEndAlloc(self.allocator, 10 * 1024 * 1024);
+        defer self.allocator.free(content);
+
+        if (content.len == 0) return error.NoRecentEntry;
+
+        // Find the last newline before EOF (to isolate the last line)
+        var last_newline: ?usize = null;
+        var second_last_newline: ?usize = null;
+        for (0..content.len) |i| {
+            const idx = content.len - 1 - i;
+            if (content[idx] == '\n') {
+                if (last_newline == null) {
+                    last_newline = idx;
+                } else {
+                    second_last_newline = idx;
+                    break;
+                }
+            }
+        }
+
+        // Determine the start of the last line
+        const last_line_start = if (second_last_newline) |idx| idx + 1 else 0;
+        const last_line_end = last_newline orelse content.len;
+        const last_line = content[last_line_start..last_line_end];
+
+        if (last_line.len == 0) return error.NoRecentEntry;
+
+        // Parse the entry
+        var entry = try parseConversationEntry(self.allocator, last_line);
+        defer entry.deinit(self.allocator);
+
+        // Update quality
+        entry.quality = quality;
+
+        // Serialize the updated entry
+        const new_jsonl = try entry.toJsonl(self.allocator);
+        defer self.allocator.free(new_jsonl);
+
+        // Rewrite file: everything before last line + updated last line
+        try file.seekTo(0);
+
+        if (last_line_start > 0) {
+            try file.writeAll(content[0..last_line_start]);
+        }
+        try file.writeAll(new_jsonl);
+
+        // Truncate any remaining bytes
+        try file.setEndPos(try file.getPos());
+    }
