+    // =========================================================================
+    // REM Cycle: Model Bootstrap (Memory Replay for New Models)
+    // =========================================================================
+
+    /// Detect if we need to bootstrap adapter for new model
+    /// Called on startup when switching to a model with no adapter
+    /// Returns true if bootstrap was triggered, false otherwise
+    pub fn checkModelBootstrap(self: *Hippocampus) !bool {
+        const adapter_path = try self.getAdapterPath();
+        defer self.allocator.free(adapter_path);
+
+        // Check if adapter exists for this model
+        if (std.fs.cwd().access(adapter_path, .{})) |_| {
+            logger.debug("Adapter exists for model, no bootstrap needed", .{});
+            return false; // Adapter exists, no bootstrap needed
+        } else |_| {}
+
+        // No adapter for this model - trigger REM cycle
+        logger.info("New model detected (no adapter). Starting REM bootstrap...", .{});
+
+        // Fetch ALL historical conversations (not just unconsolidated)
+        // The logs are universal text - can train any model
+        const all_history = try self.fetchAllHistory(5000);
+        defer {
+            for (all_history) |*e| e.deinit(self.allocator);
+            self.allocator.free(all_history);
+        }
+
+        if (all_history.len < self.min_new_events_for_training) {
+            logger.info("Insufficient history for bootstrap ({d} events, need {d})", .{
+                all_history.len,
+                self.min_new_events_for_training,
+            });
+            return false;
+        }
+
+        logger.info("REM bootstrap: Replaying {d} historical events", .{all_history.len});
+
+        // Format training data (applies DPO-Lite filtering)
+        const training_examples = try self.formatTrainingData(all_history, &[_]ConversationEntry{});
+        defer {
+            for (training_examples) |*ex| ex.deinit(self.allocator);
+            self.allocator.free(training_examples);
+        }
+
+        if (training_examples.len == 0) {
+            logger.warn("No valid training examples after quality filtering", .{});
+            return false;
+        }
+
+        // Create interrupt flag
+        var interrupt_flag = std.atomic.Value(bool).init(true);
+
+        // Run training
+        logger.info("Starting REM bootstrap training...", .{});
+        lora_trainer.train(self.allocator, .{
+            .model_path = self.model_path,
+            .output_path = adapter_path,
+            .resume_adapter_path = null, // Fresh adapter
+            .training_examples = training_examples,
+            .interrupt_flag = &interrupt_flag,
+            .epochs = 1, // Light training
+            .learning_rate = 0.00005,
+            .batch_size = 16,
+            .ctx_size = 1024,
+        }) catch |err| {
+            logger.err("REM bootstrap training failed: {}", .{err});
+            return err;
+        };
+
+        logger.info("REM bootstrap complete. Model now personalized from history.", .{});
+        return true;
+    }
+
+    /// Fetch all historical events (both consolidated and unconsolidated)
+    /// Used for REM bootstrap when switching to a new model
+    fn fetchAllHistory(self: *Hippocampus, limit: usize) ![]ConversationEntry {
+        var entries = try std.ArrayList(ConversationEntry).initCapacity(self.allocator, 0);
+        errdefer {
+            for (entries.items) |*e| e.deinit(self.allocator);
+            entries.deinit(self.allocator);
+        }
+
+        const dir_path = std.fs.path.dirname(self.conversation_logger.log_path) orelse
+            return entries.toOwnedSlice(self.allocator);
+
+        var dir = std.fs.cwd().openDir(dir_path, .{ .iterate = true }) catch |err| {
+            if (err == error.FileNotFound) return entries.toOwnedSlice(self.allocator);
+            return err;
+        };
+        defer dir.close();
+
+        var iter = dir.iterate();
+        while (try iter.next()) |entry| {
+            if (entry.kind != .file) continue;
+            if (!std.mem.endsWith(u8, entry.name, ".jsonl")) continue;
+
+            const file = try dir.openFile(entry.name, .{});
+            defer file.close();
+
+            const content = try file.readToEndAlloc(self.allocator, 10 * 1024 * 1024);
+            defer self.allocator.free(content);
+
+            var lines = std.mem.splitScalar(u8, content, '\n');
+            while (lines.next()) |line| {
+                if (line.len == 0) continue;
+                const parsed = @import("conversation_logger.zig").parseConversationEntry(self.allocator, line) catch continue;
+                try entries.append(self.allocator, parsed);
+                if (entries.items.len >= limit) {
+                    return entries.toOwnedSlice(self.allocator);
+                }
+            }
+        }
+
+        return entries.toOwnedSlice(self.allocator);
+    }
 };

