+// =============================================================================
+// Helper Functions
+// =============================================================================
+
+/// Extract model hash from adapter filename (convention: {hash}_{name}.lora)
+/// Returns 0 if no hash found (backward compatibility - allow loading)
+fn extractModelHashFromPath(path: []const u8) u64 {
+    const basename = std.fs.path.basename(path);
+
+    // Look for pattern: {hex_hash}_{name}.lora
+    if (std.mem.indexOf(u8, basename, "_")) |underscore_pos| {
+        const hash_str = basename[0..underscore_pos];
+        // Must be valid hex and reasonable length (8-16 chars for 32-64 bit hash)
+        if (hash_str.len >= 8 and hash_str.len <= 16) {
+            return std.fmt.parseInt(u64, hash_str, 16) catch 0;
+        }
+    }
+    return 0; // Unknown - allow loading (backward compat)
+}
+
