+    try std.testing.expectEqual(@as(u64, 0xa1b2c3d4e5f6a1b2), extractModelHashFromPath(path1));
+
+    // Valid 8-char hex hash
+    const path2 = "/path/to/deadbeef_my_adapter.lora";
+    try std.testing.expectEqual(@as(u64, 0xdeadbeef), extractModelHashFromPath(path2));
+}
