+
+    // Hash too short (less than 8 chars)
+    const path2 = "/path/to/abc_adapter.lora";
+    try std.testing.expectEqual(@as(u64, 0), extractModelHashFromPath(path2));
+
+    // Not a valid hex string
+    const path3 = "/path/to/notahexs_adapter.lora";
+    try std.testing.expectEqual(@as(u64, 0), extractModelHashFromPath(path3));
